test_cases.python_test_script:
def test_tc_gw_c05_001_crc_present(can_bus):
    msgs = collect_messages(can_bus, 0x119, 3)
    for msg in msgs:
        assert decode_crc(msg) is not None

def test_tc_gw_c05_002_crc_changes_with_data(can_bus):
    msgs = collect_messages(can_bus, 0x119, 5)
    for i in range(1, len(msgs)):
        if decode_safety_data(msgs[i]) != decode_safety_data(msgs[i - 1]):
            assert decode_crc(msgs[i]) != decode_crc(msgs[i - 1])

def test_tc_gw_c05_003_crc_stable_with_same_data(can_bus):
    msgs = collect_messages(can_bus, 0x119, 3)
    data_values = [decode_safety_data(m) for m in msgs]
    crc_values = [decode_crc(m) for m in msgs]
    if len(set(data_values)) == 1:
        assert len(set(crc_values)) == 1

def test_tc_gw_c05_004_crc_range(can_bus):
    msgs = collect_messages(can_bus, 0x119, 5)
    for msg in msgs:
        crc = decode_crc(msg)
        assert 0 <= crc <= 255

def test_tc_gw_c05_007_crc_present_in_all_frames(can_bus):
    msgs = collect_messages(can_bus, 0x119, 10)
    for msg in msgs:
        assert decode_crc(msg) is not None
